INSERT INTO period (period_id, name, slug, start_year, end_year, description, created_at, updated_at) VALUES
    (1, 'Thời Văn Lang', 'thoi-van-lang', -2879, -258, 'Giai đoạn truyền thuyết gắn với các vua Hùng và nền văn minh sông Hồng.', '2026-03-01 08:00:00', '2026-03-01 08:00:00'),
    (2, 'Thời Âu Lạc', 'thoi-au-lac', -257, -179, 'Nhà nước Âu Lạc của An Dương Vương với trung tâm Cổ Loa.', '2026-03-02 08:00:00', '2026-03-02 08:00:00'),
    (3, 'Bắc thuộc lần thứ nhất', 'bac-thuoc-lan-thu-nhat', -179, 40, 'Giai đoạn chịu sự cai trị của các triều đại phương Bắc sau Âu Lạc.', '2026-03-03 08:00:00', '2026-03-03 08:00:00'),
    (4, 'Khởi nghĩa Hai Bà Trưng', 'khoi-nghia-hai-ba-trung', 40, 43, 'Thời kỳ giành quyền tự chủ ngắn ngủi do Hai Bà Trưng lãnh đạo.', '2026-03-04 08:00:00', '2026-03-04 08:00:00'),
    (5, 'Nhà Tiền Lý và Vạn Xuân', 'nha-tien-ly-van-xuan', 544, 602, 'Nhà nước Vạn Xuân do Lý Bí thành lập.', '2026-03-05 08:00:00', '2026-03-05 08:00:00'),
    (6, 'Họ Khúc - họ Dương', 'ho-khuc-ho-duong', 905, 938, 'Giai đoạn đặt nền tự chủ trước chiến thắng Bạch Đằng.', '2026-03-06 08:00:00', '2026-03-06 08:00:00'),
    (7, 'Nhà Ngô', 'nha-ngo', 939, 965, 'Triều đại độc lập đầu tiên sau hơn một thiên niên kỷ Bắc thuộc.', '2026-03-07 08:00:00', '2026-03-07 08:00:00'),
    (8, 'Nhà Đinh', 'nha-dinh', 968, 980, 'Triều đại thống nhất đất nước sau loạn mười hai sứ quân.', '2026-03-08 08:00:00', '2026-03-08 08:00:00'),
    (9, 'Nhà Tiền Lê', 'nha-tien-le', 980, 1009, 'Triều đại gắn với kháng chiến chống Tống lần thứ nhất.', '2026-03-09 08:00:00', '2026-03-09 08:00:00'),
    (10, 'Nhà Lý', 'nha-ly', 1009, 1225, 'Thời kỳ xây dựng quốc gia Đại Việt và kinh đô Thăng Long.', '2026-03-10 08:00:00', '2026-03-10 08:00:00'),
    (11, 'Nhà Trần', 'nha-tran', 1225, 1400, 'Triều đại nổi bật với ba lần kháng chiến chống Nguyên Mông.', '2026-03-11 08:00:00', '2026-03-11 08:00:00'),
    (12, 'Nhà Hồ', 'nha-ho', 1400, 1407, 'Triều đại cải cách ngắn ngủi trước cuộc xâm lược của nhà Minh.', '2026-03-12 08:00:00', '2026-03-12 08:00:00'),
    (13, 'Bắc thuộc lần thứ tư', 'bac-thuoc-lan-thu-tu', 1407, 1427, 'Giai đoạn nhà Minh đô hộ Đại Việt.', '2026-03-13 08:00:00', '2026-03-13 08:00:00'),
    (14, 'Nhà Hậu Lê', 'nha-hau-le', 1428, 1789, 'Triều đại kéo dài với nhiều biến động chính trị và văn hóa.', '2026-03-14 08:00:00', '2026-03-14 08:00:00'),
    (15, 'Nhà Mạc', 'nha-mac', 1527, 1592, 'Triều đại do Mạc Đăng Dung lập nên trong bối cảnh Lê sơ suy yếu.', '2026-03-15 08:00:00', '2026-03-15 08:00:00'),
    (16, 'Trịnh - Nguyễn phân tranh', 'trinh-nguyen-phan-tranh', 1627, 1672, 'Thời kỳ chia cắt Đàng Ngoài và Đàng Trong.', '2026-03-16 08:00:00', '2026-03-16 08:00:00'),
    (17, 'Phong trào Tây Sơn', 'phong-trao-tay-son', 1771, 1802, 'Phong trào nông dân và triều đại Tây Sơn cuối thế kỷ XVIII.', '2026-03-17 08:00:00', '2026-03-17 08:00:00'),
    (18, 'Nhà Nguyễn', 'nha-nguyen', 1802, 1945, 'Triều đại quân chủ cuối cùng của Việt Nam.', '2026-03-18 08:00:00', '2026-03-18 08:00:00'),
    (19, 'Thời Pháp thuộc', 'thoi-phap-thuoc', 1858, 1945, 'Giai đoạn Việt Nam chịu sự cai trị của thực dân Pháp.', '2026-03-19 08:00:00', '2026-03-19 08:00:00'),
    (20, 'Việt Nam hiện đại', 'viet-nam-hien-dai', 1945, NULL, 'Giai đoạn từ Cách mạng tháng Tám đến hiện nay.', '2026-03-20 08:00:00', '2026-03-20 08:00:00');
INSERT INTO person (person_id, name, slug, alias, birth_date, death_date, biography, created_at, updated_at) VALUES
    (1, 'Hùng Vương', 'hung-vuong', 'Các vua Hùng', NULL, NULL, 'Hùng Vương là danh xưng truyền thống của các thủ lĩnh Văn Lang trong buổi đầu lịch sử Việt Nam.', '2026-04-01 08:00:00', '2026-04-01 08:00:00'),
    (2, 'An Dương Vương', 'an-duong-vuong', 'Thục Phán', NULL, NULL, 'An Dương Vương được gắn với nhà nước Âu Lạc và thành Cổ Loa.', '2026-04-02 08:00:00', '2026-04-02 08:00:00'),
    (3, 'Trưng Trắc', 'trung-trac', 'Hai Bà Trưng', NULL, NULL, 'Trưng Trắc là một trong hai thủ lĩnh cuộc khởi nghĩa chống Đông Hán năm 40.', '2026-04-03 08:00:00', '2026-04-03 08:00:00'),
    (4, 'Trưng Nhị', 'trung-nhi', 'Hai Bà Trưng', NULL, NULL, 'Trưng Nhị cùng Trưng Trắc lãnh đạo cuộc khởi nghĩa giành quyền tự chủ.', '2026-04-04 08:00:00', '2026-04-04 08:00:00'),
    (5, 'Bà Triệu', 'ba-trieu', 'Triệu Thị Trinh', NULL, NULL, 'Bà Triệu lãnh đạo cuộc khởi nghĩa chống ách đô hộ Đông Ngô ở thế kỷ III.', '2026-04-05 08:00:00', '2026-04-05 08:00:00'),
    (6, 'Lý Bí', 'ly-bi', 'Lý Nam Đế', NULL, NULL, 'Lý Bí lập nước Vạn Xuân, khẳng định ý chí độc lập của người Việt.', '2026-04-06 08:00:00', '2026-04-06 08:00:00'),
    (7, 'Mai Thúc Loan', 'mai-thuc-loan', 'Mai Hắc Đế', NULL, NULL, 'Mai Thúc Loan lãnh đạo cuộc khởi nghĩa lớn chống nhà Đường.', '2026-04-07 08:00:00', '2026-04-07 08:00:00'),
    (8, 'Ngô Quyền', 'ngo-quyen', NULL, NULL, NULL, 'Ngô Quyền đánh bại quân Nam Hán trên sông Bạch Đằng năm 938.', '2026-04-08 08:00:00', '2026-04-08 08:00:00'),
    (9, 'Đinh Bộ Lĩnh', 'dinh-bo-linh', 'Đinh Tiên Hoàng', NULL, NULL, 'Đinh Bộ Lĩnh dẹp loạn mười hai sứ quân và lập nhà Đinh.', '2026-04-09 08:00:00', '2026-04-09 08:00:00'),
    (10, 'Lê Hoàn', 'le-hoan', 'Lê Đại Hành', NULL, '1005-01-01', 'Lê Hoàn lãnh đạo Đại Cồ Việt chống quân Tống năm 981.', '2026-04-10 08:00:00', '2026-04-10 08:00:00'),
    (11, 'Lý Thái Tổ', 'ly-thai-to', 'Lý Công Uẩn', NULL, '1028-03-31', 'Lý Thái Tổ sáng lập nhà Lý và dời đô ra Thăng Long.', '2026-04-11 08:00:00', '2026-04-11 08:00:00'),
    (12, 'Lý Thường Kiệt', 'ly-thuong-kiet', NULL, '1019-01-01', '1105-01-01', 'Lý Thường Kiệt chỉ huy kháng chiến chống Tống và gắn với bài Nam quốc sơn hà.', '2026-04-12 08:00:00', '2026-04-12 08:00:00'),
    (13, 'Trần Hưng Đạo', 'tran-hung-dao', 'Hưng Đạo Đại Vương', '1228-01-01', '1300-01-01', 'Trần Hưng Đạo là danh tướng chỉ huy kháng chiến chống Nguyên Mông.', '2026-04-13 08:00:00', '2026-04-13 08:00:00'),
    (14, 'Trần Nhân Tông', 'tran-nhan-tong', NULL, '1258-12-07', '1308-12-16', 'Trần Nhân Tông là vua nhà Trần và người sáng lập Thiền phái Trúc Lâm.', '2026-04-14 08:00:00', '2026-04-14 08:00:00'),
    (15, 'Lê Lợi', 'le-loi', 'Lê Thái Tổ', '1385-09-10', '1433-09-05', 'Lê Lợi lãnh đạo khởi nghĩa Lam Sơn và lập nhà Hậu Lê.', '2026-04-15 08:00:00', '2026-04-15 08:00:00'),
    (16, 'Nguyễn Trãi', 'nguyen-trai', 'Ức Trai', '1380-01-01', '1442-09-19', 'Nguyễn Trãi là nhà chính trị, quân sự và văn hóa lớn thời Lê sơ.', '2026-04-16 08:00:00', '2026-04-16 08:00:00'),
    (17, 'Quang Trung', 'quang-trung', 'Nguyễn Huệ', '1753-01-01', '1792-09-16', 'Quang Trung là hoàng đế Tây Sơn, đánh thắng quân Thanh năm 1789.', '2026-04-17 08:00:00', '2026-04-17 08:00:00'),
