    (7, 6, 'Khúc Thừa Dụ giành quyền tự chủ', 'khuc-thua-du-gianh-quyen-tu-chu', 'Họ Khúc đặt nền móng tự chủ ở đầu thế kỷ X.', 905, 905, NULL, NULL, 'CERTAIN', '2026-06-07 08:00:00', '2026-06-07 08:00:00'),
    (8, 7, 'Chiến thắng Bạch Đằng năm 938', 'chien-thang-bach-dang-938', 'Ngô Quyền đánh bại quân Nam Hán trên sông Bạch Đằng.', 938, 938, NULL, NULL, 'CERTAIN', '2026-06-08 08:00:00', '2026-06-08 08:00:00'),
    (9, 8, 'Đinh Bộ Lĩnh thống nhất đất nước', 'dinh-bo-linh-thong-nhat-dat-nuoc', 'Đinh Bộ Lĩnh dẹp loạn mười hai sứ quân, lập nước Đại Cồ Việt.', 968, 968, NULL, NULL, 'CERTAIN', '2026-06-09 08:00:00', '2026-06-09 08:00:00'),
