    (16, 13, 'Khởi nghĩa Lam Sơn', 'khoi-nghia-lam-son', 'Lê Lợi lãnh đạo cuộc khởi nghĩa chống Minh từ Lam Sơn.', 1418, 1427, '1418-01-01', '1427-12-31', 'CERTAIN', '2026-06-16 08:00:00', '2026-06-16 08:00:00'),
