INSERT INTO post (post_id, admin_id, event_id, title, slug, summary, content, thumbnail_url, status, published_at, created_at, updated_at) VALUES
    (1, 1, 1, 'Văn Lang trong ký ức lịch sử', 'van-lang-trong-ky-uc-lich-su', 'Tóm lược nguồn gốc Văn Lang và truyền thống Hùng Vương.', 'Bài viết giới thiệu bối cảnh hình thành nhà nước Văn Lang, các truyền thuyết Hùng Vương và giá trị văn hóa còn lưu lại.', '/images/posts/van-lang.jpg', 'PUBLISHED', '2026-07-01 09:00:00', '2026-07-01 08:00:00', '2026-07-01 09:00:00'),
    (2, 2, 2, 'Cổ Loa và dấu ấn Âu Lạc', 'co-loa-va-dau-an-au-lac', 'Khám phá vai trò của Cổ Loa trong thời Âu Lạc.', 'Cổ Loa là một trung tâm quyền lực cổ với cấu trúc thành lũy đặc biệt và nhiều lớp truyền thuyết lịch sử.', '/images/posts/co-loa.jpg', 'PUBLISHED', '2026-07-02 09:00:00', '2026-07-02 08:00:00', '2026-07-02 09:00:00'),
    (3, 3, 3, 'Âu Lạc sau năm 179 trước Công nguyên', 'au-lac-sau-nam-179-truoc-cong-nguyen', 'Bối cảnh Âu Lạc rơi vào quyền kiểm soát của Nam Việt.', 'Bài viết phân tích sự kiện Triệu Đà thôn tính Âu Lạc và hệ quả chính trị trong khu vực.', '/images/posts/au-lac.jpg', 'PUBLISHED', '2026-07-03 09:00:00', '2026-07-03 08:00:00', '2026-07-03 09:00:00'),
    (4, 4, 4, 'Hai Bà Trưng và khát vọng tự chủ', 'hai-ba-trung-va-khat-vong-tu-chu', 'Cuộc khởi nghĩa năm 40 trong mạch lịch sử chống đô hộ.', 'Hai Bà Trưng trở thành biểu tượng của tinh thần tự chủ và vai trò phụ nữ trong lịch sử Việt Nam.', '/images/posts/hai-ba-trung.jpg', 'PUBLISHED', '2026-07-04 09:00:00', '2026-07-04 08:00:00', '2026-07-04 09:00:00'),
    (5, 5, 5, 'Bà Triệu trong thế kỷ III', 'ba-trieu-trong-the-ky-iii', 'Nhìn lại cuộc khởi nghĩa chống Đông Ngô.', 'Bài viết trình bày bối cảnh, diễn biến và hình tượng Bà Triệu trong ký ức dân gian.', '/images/posts/ba-trieu.jpg', 'PUBLISHED', '2026-07-05 09:00:00', '2026-07-05 08:00:00', '2026-07-05 09:00:00'),
    (6, 6, 6, 'Vạn Xuân và tuyên ngôn độc lập sớm', 'van-xuan-va-tuyen-ngon-doc-lap-som', 'Lý Bí lập nước Vạn Xuân trong thế kỷ VI.', 'Sự kiện Lý Bí lập nước Vạn Xuân phản ánh nỗ lực xây dựng một chính quyền độc lập.', '/images/posts/van-xuan.jpg', 'PUBLISHED', '2026-07-06 09:00:00', '2026-07-06 08:00:00', '2026-07-06 09:00:00'),
    (7, 7, 7, 'Họ Khúc và nền tự chủ', 'ho-khuc-va-nen-tu-chu', 'Vai trò của Khúc Thừa Dụ trong quá trình giành tự chủ.', 'Họ Khúc đặt nền móng quan trọng cho quyền tự chủ trước chiến thắng Bạch Đằng.', '/images/posts/ho-khuc.jpg', 'PUBLISHED', '2026-07-07 09:00:00', '2026-07-07 08:00:00', '2026-07-07 09:00:00'),
    (8, 8, 8, 'Bạch Đằng 938', 'bach-dang-938', 'Chiến thắng của Ngô Quyền và bước ngoặt độc lập.', 'Trận Bạch Đằng năm 938 mở ra kỷ nguyên độc lập lâu dài cho dân tộc Việt.', '/images/posts/bach-dang-938.jpg', 'PUBLISHED', '2026-07-08 09:00:00', '2026-07-08 08:00:00', '2026-07-08 09:00:00'),
    (9, 9, 9, 'Đinh Bộ Lĩnh và công cuộc thống nhất', 'dinh-bo-linh-va-cong-cuoc-thong-nhat', 'Dẹp loạn mười hai sứ quân và lập Đại Cồ Việt.', 'Đinh Bộ Lĩnh thống nhất đất nước, đặt nền tảng cho nhà nước quân chủ độc lập.', '/images/posts/dinh-bo-linh.jpg', 'PUBLISHED', '2026-07-09 09:00:00', '2026-07-09 08:00:00', '2026-07-09 09:00:00'),
    (10, 10, 10, 'Lê Hoàn và cuộc chiến năm 981', 'le-hoan-va-cuoc-chien-981', 'Kháng chiến chống Tống dưới thời Tiền Lê.', 'Cuộc kháng chiến năm 981 củng cố vị thế Đại Cồ Việt trong khu vực.', '/images/posts/le-hoan.jpg', 'PUBLISHED', '2026-07-10 09:00:00', '2026-07-10 08:00:00', '2026-07-10 09:00:00'),
    (11, 11, 11, 'Thăng Long từ Chiếu dời đô', 'thang-long-tu-chieu-doi-do', 'Lý Thái Tổ và quyết định dời đô năm 1010.', 'Việc dời đô ra Thăng Long đánh dấu tầm nhìn chiến lược trong xây dựng quốc gia Đại Việt.', '/images/posts/thang-long.jpg', 'PUBLISHED', '2026-07-11 09:00:00', '2026-07-11 08:00:00', '2026-07-11 09:00:00'),
    (12, 12, 12, 'Phòng tuyến Như Nguyệt', 'phong-tuyen-nhu-nguyet', 'Lý Thường Kiệt trong kháng chiến chống Tống.', 'Phòng tuyến Như Nguyệt là một dấu mốc quân sự quan trọng thời Lý.', '/images/posts/nhu-nguyet.jpg', 'PUBLISHED', '2026-07-12 09:00:00', '2026-07-12 08:00:00', '2026-07-12 09:00:00'),
    (13, 13, 13, 'Nhà Trần trước thử thách Nguyên Mông', 'nha-tran-truoc-thu-thach-nguyen-mong', 'Cuộc kháng chiến năm 1258 và kinh nghiệm phòng thủ.', 'Nhà Trần vận dụng kế sách linh hoạt để đẩy lui quân Nguyên trong lần xâm lược đầu tiên.', '/images/posts/tran-1258.jpg', 'PUBLISHED', '2026-07-13 09:00:00', '2026-07-13 08:00:00', '2026-07-13 09:00:00'),
    (14, 14, 14, 'Bạch Đằng 1288', 'bach-dang-1288', 'Trận quyết chiến dưới sự chỉ huy của Trần Hưng Đạo.', 'Chiến thắng Bạch Đằng năm 1288 kết thúc thắng lợi cuộc kháng chiến chống Nguyên Mông.', '/images/posts/bach-dang-1288.jpg', 'PUBLISHED', '2026-07-14 09:00:00', '2026-07-14 08:00:00', '2026-07-14 09:00:00'),
    (15, 15, 15, 'Cải cách thời Hồ Quý Ly', 'cai-cach-thoi-ho-quy-ly', 'Nhìn lại triều Hồ và những cải cách gây tranh luận.', 'Nhà Hồ tồn tại ngắn ngủi nhưng để lại nhiều vấn đề nghiên cứu về cải cách nhà nước.', '/images/posts/nha-ho.jpg', 'DRAFT', NULL, '2026-07-15 08:00:00', '2026-07-15 08:00:00'),
    (16, 16, 16, 'Lam Sơn từ khởi nghĩa đến thắng lợi', 'lam-son-tu-khoi-nghia-den-thang-loi', 'Hành trình chống Minh của nghĩa quân Lam Sơn.', 'Khởi nghĩa Lam Sơn đi từ căn cứ địa Thanh Hóa đến thắng lợi giải phóng đất nước.', '/images/posts/lam-son.jpg', 'PUBLISHED', '2026-07-16 09:00:00', '2026-07-16 08:00:00', '2026-07-16 09:00:00'),
    (17, 17, 17, 'Bình Ngô đại cáo và ý thức quốc gia', 'binh-ngo-dai-cao-va-y-thuc-quoc-gia', 'Tác phẩm chính luận sau thắng lợi Lam Sơn.', 'Bình Ngô đại cáo khẳng định nền độc lập và tư tưởng chính nghĩa trong lịch sử Đại Việt.', '/images/posts/binh-ngo-dai-cao.jpg', 'PUBLISHED', '2026-07-17 09:00:00', '2026-07-17 08:00:00', '2026-07-17 09:00:00'),
    (18, 18, 18, 'Ngọc Hồi - Đống Đa mùa xuân 1789', 'ngoc-hoi-dong-da-mua-xuan-1789', 'Chiến thắng của Quang Trung trước quân Thanh.', 'Chiến dịch thần tốc mùa xuân Kỷ Dậu là đỉnh cao quân sự của phong trào Tây Sơn.', '/images/posts/dong-da.jpg', 'PUBLISHED', '2026-07-18 09:00:00', '2026-07-18 08:00:00', '2026-07-18 09:00:00'),
    (19, 19, 19, 'Đà Nẵng 1858 và bước ngoặt cận đại', 'da-nang-1858-va-buoc-ngoat-can-dai', 'Sự kiện mở đầu quá trình Pháp xâm lược Việt Nam.', 'Cuộc tấn công Đà Nẵng năm 1858 mở ra một thời kỳ biến động sâu sắc.', '/images/posts/da-nang-1858.jpg', 'ARCHIVED', '2026-07-19 09:00:00', '2026-07-19 08:00:00', '2026-07-19 09:00:00'),
    (20, 20, 20, 'Điện Biên Phủ trong lịch sử hiện đại', 'dien-bien-phu-trong-lich-su-hien-dai', 'Chiến thắng năm 1954 và ý nghĩa quốc tế.', 'Điện Biên Phủ là thắng lợi quân sự quyết định, dẫn tới Hiệp định Genève năm 1954.', '/images/posts/dien-bien-phu.jpg', 'PUBLISHED', '2026-07-20 09:00:00', '2026-07-20 08:00:00', '2026-07-20 09:00:00');
